1149→// StartTime implements the Storage interface.
1150→func (db *DB) StartTime() (int64, error) {
1151→	db.mtx.RLock()
1152→	defer db.mtx.RUnlock()
1153→
1154→	if len(db.blocks) > 0 {
1155→		return db.blocks[0].Meta().MinTime, nil
1156→	}
1157→	return db.head.MinTime(), nil
1158→}
