### 9. DB.COMPACT() - MAIN COMPACTION METHOD
**File:** `/workspace/go/agent-index-go/testdata/fixtures/go/db.go:1414-1506`

```go
func (db *DB) Compact(ctx context.Context) (returnErr error) {
    db.cmtx.Lock()           // ← Exclusive lock (compactions & deletions don't overlap)
    defer db.cmtx.Unlock()

    // Phase 1: COMPACT HEAD BLOCKS
    for {
        // Stop if head no longer compactable
        if !db.head.compactable() {
            break
        }

        // Wait for compaction delay (if enabled)
        if db.waitingForCompactionDelay() {
            break
        }

        // Create RangeHead for time window
        mint := db.head.MinTime()
        maxt := rangeForTimestamp(mint, db.head.chunkRange.Load())
        rh := NewRangeHeadWithIsolationDisabled(db.head, mint, maxt-1)

        // Wait for any overlapping appenders to finish
        db.head.WaitForAppendersOverlapping(rh.MaxTime())

        // Compact the head block
        if err := db.compactHead(rh); err != nil {
            return fmt.Errorf("compact head: %w", err)
        }
        lastBlockMaxt = maxt
    }

    // Phase 2: TRUNCATE WAL
    if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
        return fmt.Errorf("WAL truncation: %w", err)
    }

    // Phase 3: COMPACT OUT-OF-ORDER HEAD
    if lastBlockMaxt != math.MinInt64 {
        if err := db.compactOOOHead(ctx); err != nil {
            return fmt.Errorf("compact ooo head: %w", err)
        }
    }

    // Phase 4: COMPACT BLOCKS
    return db.compactBlocks()
}
