```go
func (db *DB) compactBlocks() (err error) {
    for {
        // Check if head became compactable during block compaction
        if db.head.compactable() && !db.waitingForCompactionDelay() {
            db.logger.Warn("aborting block compactions to persist the head block")
            return nil  // ← Abort to prioritize head compaction
        }

        // Step 1: GET COMPACTION PLAN
        plan, err := db.compactor.Plan(db.dir)
        if err != nil {
            return fmt.Errorf("plan compaction: %w", err)
        }
        if len(plan) == 0 {
            break  // No more blocks to compact
        }

        // Step 2: PERFORM COMPACTION
        uids, err := db.compactor.Compact(db.dir, plan, db.blocks)
        if err != nil {
            return fmt.Errorf("compact %s: %w", plan, err)
        }

        // Step 3: RELOAD BLOCKS
        if err := db.reloadBlocks(); err != nil {
            // Cleanup on error
            for _, uid := range uids {
                os.RemoveAll(filepath.Join(db.dir, uid.String()))
            }
            return errors.Join(errs...)
        }
    }
    return nil
}
